DROP TRIGGER IF EXISTS tbiu_sc_lon_m_loan_req_mpaid ON sc_lon_m_loan_request_mpaid CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_lon_m_loan_req_mpaid() RETURNS trigger AS $BODY$
declare
  ls_close_status char;
BEGIN
  BEGIN
  if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_lon_m_loan_request_mpaid
    where loan_requestment_no = NEW.loan_requestment_no;
    NEW.seq_no := coalesce(NEW.seq_no,0) +1;
  end if;
  if coalesce(NEW.paid_amount::text, '') = '' then NEW.paid_amount := 0;end if;

  if NEW.type_pay_money = 'TRB' and ( coalesce(NEW.bank_code::text, '') = '' or NEW.bank_code = '' ) then NEW.bank_code := '06';end if;

  --Niorn 2024-06-26 TGE
  if NEW.bank_code = '000' then
    null;
    -- บัญชีเงินฝาก สอ.
    if coalesce(OLD.bank_acc_no,' ') <> coalesce(NEW.bank_acc_no,' ') then
      BEGIN
        select close_status into STRICT ls_close_status
        from sc_dep_m_creditor
        where (deposit_account_no = NEW.bank_acc_no);
      exception when others then CALL spa_dberror('E29:บัญชีเงินฝาก('||trim(both NEW.bank_acc_no)||'),ไม่มีอยู่จริง');
      end;
      if ls_close_status  = 'C' then
        CALL spa_dberror('E32:บัญชีเงินฝาก('||trim(both NEW.bank_acc_no)||'),ปิดบัญชีแล้ว');
      end if;
    end if;
  elsif NEW.bank_code = '006' then
    -- บัญชีเงินฝาก ธนาคาร
    if  length(trim(both NEW.bank_acc_no)) <> 10 then
      CALL spa_dberror('T40:เลขที่บัญชี('||trim(both NEW.bank_acc_no)||'), บัญชีธนาคารต้องเป็น 10 หลักเท่านั้น');
    end if;
  end if;


  END;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
